// sumArr.js
function sumArr(arr) {
  // Ensure we only sum numeric values
  return arr.reduce((total, val) => {
    return typeof val === 'number' && !isNaN(val) ? total + val : total;
  }, 0);
}

// Export the function for Node.js/CommonJS environments
module.exports = sumArr;
```

**How it works**

- `Array.prototype.reduce` iterates through the array, accumulating a running total.
- It adds the element to the total only if the element is a valid number (`typeof val === 'number' && !isNaN(val)`).  
- The initial accumulator value is `0`.
- `module.exports = sumArr;` makes the function importable with `require('./sumArr')`.

